async (params, browser) => {
  // Open page
  await browser.open(`${params.list_url}`)

  // Wait for content
  await browser.waitForSelector('table.tableList tr, [class*=\'BookListItem\']', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const listTitle = document.querySelector('h1')?.textContent?.trim()||''; const books = Array.from(document.querySelectorAll('table.tableList tr, [class*="BookListItem"]')).slice(0,50).map((row,i) => { const t = row.querySelector('a.bookTitle, a[href*="/book/show/"]'); const a = row.querySelector('a.authorName, a[href*="/author/"]'); const r = row.querySelector('[class*="minirating"]'); return { rank: i+1, title: t?t.textContent.trim():'', url: t?t.href:'', author: a?a.textContent.trim():'', rating: r?r.textContent.trim():'' }; }).filter(b=>b.title); return { list_title: listTitle, books, url: window.location.href }`)

  return page_data
}
